async function handleFreeMode(message: import("discord.js").Message): Promise<boolean> {
  const inFreeMode = await isFreeModeActive(message.channelId);
  if (!inFreeMode) return false;

  const prefix = config.PREFIX;
  const content = message.content.trim();

  // Let prefix commands be handled normally (don't intercept them here)
  if (content.startsWith(prefix)) return false;

  try {
    const trainingData = await loadTrainingData();
    const basePrompt = trainingData.compiledIdentity || trainingData.baseIdentity;
    const systemPrompt = await buildAutonomousSystemPrompt(basePrompt + FREE_MODE_SYSTEM_SUFFIX, message);

    const author = message.author;
    const display = message.member?.displayName ?? author.username;
    const channelName = "name" in message.channel ? (message.channel as { name: string }).name : "desconhecido";
    const userQuery = `[Canal: #${channelName} | ${display} (<@${author.id}>)]: ${content || "(mensagem sem texto)"}`;

    const memoryKey = message.author.id;

    await recordMessageEvent("order_received", message, content || "(mensagem sem texto)", { mode: "free", channel: message.channelId });

    const { result: rawReply, spinnerMsg } = await runWithSpinner(
      message,
      (_spinnerMsg, setStatusText) => retryOnceAfterOverload(
        () => queryOllama(systemPrompt, memoryKey, userQuery),
        async () => {
          setStatusText(`${formatFwpError(new Error("503 unavailable"))}\n\nVou tentar cobrar a resposta de novo em 10s...`);
          await wait(10_000);
          setStatusText(null);
        }
      )
    );

    const firstPass = await executeFwpActions(message, rawReply);
    let allReports = [...firstPass.reports];
    let finalRawReply = rawReply;

    if (firstPass.fileReads.length > 0) {
      try {
        const followUpQuery = buildFileReadFollowUp(firstPass.fileReads);
        const secondRaw = await queryOllama(systemPrompt, memoryKey, followUpQuery);
        const secondPass = await executeFwpActions(message, secondRaw);
        allReports = [...allReports, ...secondPass.reports];
        if (!stripFwpActionBlocks(secondRaw).startsWith("[SILENT]")) {
          finalRawReply = secondRaw;
        }
      } catch (err) {
        logger.warn({ err }, "Free mode: segunda passada de leitura falhou");
      }
    }

    const reply = stripFwpActionBlocks(finalRawReply);

    await spinnerMsg.delete().catch(() => {});

    if (reply.startsWith("[SILENT]")) {
      logger.info({ channel: message.channelId }, "Free mode: Fawers optou por silĂȘncio");
      return true;
    }

    const finalReply = allReports.length > 0 ? `${reply}\n\n${allReports.join("\n")}` : reply;
    await message.channel.send(truncate(finalReply, 1900));
    logger.info({ channel: message.channelId, author: author.id }, "Free mode: resposta enviada");
  } catch (err) {
    logger.error({ err }, "Free mode: falha ao gerar resposta");
  }

  return true;
}

async function handleDM(message: import("discord.js").Message): Promise<boolean> {
  if (message.guild) return false;

  // Partial messages (DMs) may arrive without content â fetch the full message first
  if (message.partial) {
    try { message = await message.fetch(); } catch { return true; }
  }

  if (message.author?.bot) return false;

  const content = message.content?.trim() ?? "";
  if (!content) return true;

  // Allow ;setup fwp command in DMs
  const prefix = config.PREFIX;
  if (content.startsWith(prefix)) {
    const args = content.slice(prefix.length).trim().split(/\s+/);
    const cmd = args[0]?.toLowerCase();

    if (cmd === "setup" && args[1]?.toLowerCase() === "fwp") {
      if (!isFreeModeOwner(message.author.id)) {
        await message.reply({ embeds: [buildEmbed("Acesso negado", "Sem permissĂŁo para acessar o setup.", "warn")] });
        return true;
      }
      const row = new ActionRowBuilder<ButtonBuilder>().addComponents(
        new ButtonBuilder().setCustomId("fwp_model_beta").setLabel("Modelo Beta").setStyle(ButtonStyle.Secondary),
        new ButtonBuilder().setCustomId("fwp_model_v2").setLabel("FAWER_V2.01").setStyle(ButtonStyle.Primary),
        new ButtonBuilder().setCustomId("fwp_model_v3").setLabel("FAWER Flash V3.0").setStyle(ButtonStyle.Success),
        new ButtonBuilder().setCustomId("fwp_model_v4").setLabel("FAWER V4 (ChatGPT)").setStyle(ButtonStyle.Danger)
      );
      const embed = buildEmbed("Setup â Fawers", "Qual versĂŁo da Fawers vocĂȘ quer ativar?", "info");
      await message.reply({ embeds: [embed], components: [row] });
      return true;
    }

    if (cmd === "fwp" && args[1]?.toLowerCase() === "limpar") {
      await clearUserMemory(message.author.id);
      await message.reply({ embeds: [buildEmbed("MemĂłria", "MemĂłria apagada.", "ok")] });
      return true;
    }

    // If prefix but unknown command in DM, just treat the whole thing as AI query
  }

  try {
    const trainingData = await loadTrainingData();
    const systemPrompt = trainingData.compiledIdentity || trainingData.baseIdentity;
    const memoryKey = message.author.id;

    await message.channel.sendTyping().catch(() => {});
    const typingInterval = setInterval(() => message.channel.sendTyping().catch(() => {}), 8000);

    try {
      const raw = await retryOnceAfterOverload(
        () => queryOllama(systemPrompt, memoryKey, content),
        async () => { await wait(10_000); }
      );
      const reply = stripFwpActionBlocks(raw);
      if (!reply.startsWith("[SILENT]")) {
        await message.reply(truncate(reply, 1900));
      }
    } finally {
      clearInterval(typingInterval);
    }
  } catch (err) {
    logger.error({ err, userId: message.author.id }, "Falha ao responder DM");
    await message.reply("Eita, deu erro aqui. Tenta de novo em instantes.").catch(() => {});
  }

  return true;
}

const event: BotEvent = {
